   320→    /// DELETE with a JSON body and return deserialized response. Requires auth.
   321→    pub(crate) async fn delete_json_with_body<T: DeserializeOwned, B: Serialize>(
   322→        &self,
   323→        path: &str,
   324→        body: &B,
   325→    ) -> Result<T, Error> {
   326→        let token = self.require_auth()?;
   327→        self.throttle().await;
   328→        let url = format!("{}{}", self.base_url, path);
   329→        let resp = self
